"use strict";parserFactory.register("truyennhabo.com",()=>new TruyenParser);class TruyenParser extends Parser{constructor(){super()}async getChapterUrls(e){const r=[...e.querySelectorAll("#clwd ul a")],t=[...e.querySelectorAll("#clwd span.block")],n=[];for(let e=0;e<r.length;e++){const o=r[e],l=t[e];n.push({sourceUrl:o.href,title:l.textContent})}return n.reverse()}findContent(e){return e.querySelector("article.blog")}extractTitleImpl(e){return e.querySelector("h1")}extractAuthor(e){let r=e.querySelector("#extra-info dd");return r?.textContent??super.extractAuthor(e)}findChapterTitle(e){return e.querySelector("header h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.auto-rows-max")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div#synopsis")]}removeUnwantedElementsFromContentElement(e){e.querySelector("a").remove(),super.removeUnwantedElementsFromContentElement(e)}}